SELECT activation_key, expires_at
FROM activation_keys
WHERE user_id = 1;

SELECT COUNT(*) AS active_keys_count, MIN(created_at) AS earliest_creation
FROM activation_keys
WHERE is_active = 1;

SELECT COUNT(*) AS total_activations
FROM activations
WHERE activated = 1;

SELECT activation_key
FROM activations
WHERE activated = 1;

SELECT verification_device
FROM email_verifications
WHERE verification_id = 0;

SELECT user_name
FROM users
ORDER BY user_name;
